// // This module performs a two-input OR operation on inputs A1 and A2, and another two-input OR operation on B1 and B2. The output of the second OR operation is then inverted using a NOT gate. Finally, the module computes the output X by performing a logical OR between the output of the first OR gate and the inverted output from the NOT gate.
module top_module(
    input A1,
    input A2,
    input B1,
    input B2,
    output X
);wire and1_out;
    wire and2_out;
    wire not1_out;

    and and1 (and1_out, A1, A2);
    and and2 (and2_out, B1, B2);
    not not1 (not1_out, and2_out);

    assign X = and1_out & not1_out;

endmodule
